sequence.script:
var jwt = String(mc.getProperty('backend.jwt') || '');
var user = '';
var rawSubject = '';
var application = '';
var claimKeys = '';

function decodeBase64Url(value) {
    var alphabet =
        'ABCDEFGHIJKLMNOPQRSTUVWXYZ' +
        'abcdefghijklmnopqrstuvwxyz' +
        '0123456789+/';

    var normalized = String(value || '')
        .replace(/-/g, '+')
        .replace(/_/g, '/');

    while (normalized.length % 4 !== 0) {
        normalized += '=';
    }

    var bytes = '';
    var buffer = 0;
    var bits = 0;

    for (var i = 0; i < normalized.length; i++) {
        var ch = normalized.charAt(i);

        if (ch === '=') {
            break;
        }

        var index = alphabet.indexOf(ch);

        if (index < 0) {
            continue;
        }

        buffer = (buffer << 6) | index;
        bits += 6;

        if (bits >= 8) {
            bits -= 8;

            bytes += String.fromCharCode(
                (buffer >> bits) & 255
            );
        }
    }

    try {
        var encoded = '';

        for (var j = 0; j < bytes.length; j++) {
            var hex =
                bytes.charCodeAt(j).toString(16);

            encoded +=
                '%' +
                (hex.length === 1 ? '0' + hex : hex);
        }

        return decodeURIComponent(encoded);
    } catch (ignored) {
        return bytes;
    }
}

function normalizeUser(value) {
    if (
        value === null ||
        typeof value === 'undefined'
    ) {
        return '';
    }

    if (
        Object.prototype.toString.call(value) ===
        '[object Array]'
    ) {
        value =
            value.length > 0
                ? value[0]
                : '';
    }

    var normalized = String(value)
        .replace(/^\s+|\s+$/g, '')
        .replace(/^"+|"+$/g, '')
        .replace(/@carbon\.super$/i, '')
        .replace(/^PRIMARY\//i, '')
        .replace(/^Internal\//i, '')
        .replace(/^carbon\.super\//i, '');

    if (normalized.indexOf('/') >= 0) {
        var pieces = normalized.split('/');

        normalized =
            pieces[pieces.length - 1];
    }

    return normalized;
}

function isKnownPersonaUser(value) {
    return (
        value === 'partner.alpha' ||
        value === 'partner.beta' ||
        value === 'telco.operations' ||
        value === 'telco.product' ||
        value === 'telco.admin' ||
        value === 'admin'
    );
}

try {
    var token = jwt;

    /*
     * Support both a direct signed JWT and an additional
     * Base64-encoded JWT representation.
     */
    if (
        token.indexOf('.') < 0 &&
        token.length > 0
    ) {
        var decodedOuter =
            decodeBase64Url(token);

        if (
            decodedOuter.indexOf('.') >= 0
        ) {
            token = decodedOuter;
        }
    }

    var parts = token.split('.');

    if (parts.length >= 2) {
        var claims = JSON.parse(
            decodeBase64Url(parts[1])
        );

        var keys = [];

        for (var claimName in claims) {
            if (
                Object.prototype
                    .hasOwnProperty
                    .call(claims, claimName)
            ) {
                keys.push(claimName);
            }
        }

        claimKeys = keys.join(',');

        /*
         * Explicit end-user claims must take precedence
         * over sub. sub can contain a different subject
         * representation depending on token configuration.
         */
        var candidates = [
            claims[
                'http://wso2.org/claims/enduser'
            ],
            claims[
                'http://wso2.org/claims/username'
            ],
            claims[
                'http://wso2.org/claims/userid'
            ],
            claims.preferred_username,
            claims.username,
            claims.sub
        ];

        rawSubject = String(
            claims[
                'http://wso2.org/claims/enduser'
            ] ||
            claims[
                'http://wso2.org/claims/username'
            ] ||
            claims.preferred_username ||
            claims.username ||
            claims.sub ||
            ''
        );

        for (
            var candidateIndex = 0;
            candidateIndex < candidates.length;
            candidateIndex++
        ) {
            var candidate = normalizeUser(
                candidates[candidateIndex]
            );

            if (
                isKnownPersonaUser(candidate)
            ) {
                user = candidate;
                break;
            }
        }

        if (!user) {
            user = normalizeUser(rawSubject);
        }

        application = String(
            claims.application ||
            claims.applicationname ||
            claims[
                'http://wso2.org/claims/applicationname'
            ] ||
            ''
        );
    }
} catch (error) {
    mc.setProperty(
        'backend.jwt.decode.error',
        String(error)
    );
}

mc.setProperty(
    'backend.jwt.subject.raw',
    rawSubject
);

mc.setProperty(
    'backend.jwt.claim.keys',
    claimKeys
);

mc.setProperty(
    'authenticated.user',
    user
);

mc.setProperty(
    'authenticated.application',
    application
);

var persona = '';
var partner = '';
var countries = '';

if (user === 'partner.alpha') {
    persona = 'partner';
    partner = 'partner-alpha';
    countries = 'BR';
} else if (user === 'partner.beta') {
    persona = 'partner';
    partner = 'partner-beta';
    countries = 'MX';
} else if (user === 'telco.operations') {
    persona = 'operations';
    partner = '*';
    countries = 'BR,MX,CO,AR,PE,CL';
} else if (user === 'telco.product') {
    persona = 'product_manager';
    partner = '*';
    countries = 'BR,MX,CO,AR,PE,CL';
} else if (
    user === 'telco.admin' ||
    user === 'admin'
) {
    persona = 'platform_administrator';
    partner = '*';
    countries = '*';
}

mc.setProperty(
    'persona',
    persona
);

mc.setProperty(
    'authorized.partner.id',
    partner
);

mc.setProperty(
    'authorized.countries',
    countries
);
